#include <stdio.h>
#include <sys/stat.h>

int main(void) {
    struct stat sb;
    const char *path = "/tmp/kf_test_stat";
    FILE *f = fopen(path, "w");
    if (!f) { perror("fopen"); return 1; }
    fprintf(f, "hello world");
    fclose(f);
    if (stat(path, &sb) == -1) {
        perror("stat");
        return 1;
    }
    printf("Taille : %ld octets\n", (long)sb.st_size);
    printf("Est un fichier : %d\n", S_ISREG(sb.st_mode) ? 1 : 0);
    printf("Est un repertoire : %d\n", S_ISDIR(sb.st_mode) ? 1 : 0);
    remove(path);
    return 0;
}

