#include <sys/stat.h>

/* == EXEMPLE ================================================
 * Utiliser stat() pour verifier si un chemin est un repertoire
 * stat() remplit une struct stat avec les metadonnees.
 * S_ISDIR() teste le type via st_mode.
 * =========================================================== */
void example_check_dir(void) {
    struct stat sb;
    if (stat("/tmp", &sb) == -1) {
        perror("stat");
        return;
    }
    printf("/tmp est un repertoire : %d\n", S_ISDIR(sb.st_mode) ? 1 : 0);
    printf("Permissions : %o\n", sb.st_mode & 0777);
}
